     3→import { loadBlpDataUrl } from "../utils/glueButton";
     4→
     5→const FALLBACK_ICON = "/buttons/command/BTNSkillz.blp";
     6→
     7→function SkillIcon({ pick, isLast }: { pick: SkillPick; isLast: boolean }) {
     8→  const [iconUrl, setIconUrl] = useState("");
     9→
    10→  useEffect(() => {
    11→    const path = pick.icon || FALLBACK_ICON;
    12→    void loadBlpDataUrl(path)
    13→      .then(setIconUrl)
    14→      .catch(() => {
    15→        if (pick.icon) void loadBlpDataUrl(FALLBACK_ICON).then(setIconUrl);
    16→      });
    17→  }, [pick.icon]);
    18→
    19→  return (
    20→    <div className="skill-pick">
    21→      <div className="skill-pick-content">
    22→        <div className="skill-pick-icon-wrapper">
    23→          <div className="skill-pick-level">Lv{pick.level}</div>
    24→          {iconUrl ? (
    25→            <img src={iconUrl} alt={pick.skill} className="skill-pick-icon" />
    26→          ) : (
    27→            <div className="skill-pick-icon skill-pick-icon--placeholder" />
    28→          )}
    29→        </div>
    30→        <div className="skill-pick-name">{pick.skill}</div>
    31→      </div>
    32→      {!isLast && <div className="skill-pick-connector" />}
    33→    </div>
    34→  );
    35→}
    36→
    37→interface Props {
    38→  skillOrder: SkillPick[];
    39→}
    40→
    41→export default function SkillOrderSection({ skillOrder }: Props) {
    42→  if (skillOrder.length === 0) return null;
    43→
    44→  return (
    45→    <section className="section-card skill-order-section">
    46→      <h4 className="skill-order-title">Skill Order</h4>
    47→      <div className="skill-order-row">
    48→        {skillOrder.map((pick, i) => (
    49→          <SkillIcon key={i} pick={pick} isLast={i === skillOrder.length - 1} />
    50→        ))}
    51→      </div>
    52→    </section>
    53→  );
    54→}
